public double[] repairAndDecode(final double[] x) {
    if (x == null) {
        throw new IllegalArgumentException("Input array cannot be null");
    }
    double[] clippedResult = clipToBounds(x, -1e6, 0.5);
    return clippedResult;
}

private double[] clipToBounds(double[] values, double lowerBound, double upperBound) {
    for (int i = 0; i < values.length; i++) {
        values[i] = Math.max(lowerBound, Math.min(values[i], upperBound));
    }
    return values;
}
